export default{async fetch(request){var url=new URL(request.url),path=url.pathname.replace(/\/+$/,"")||"/",origin=request.headers.get("Origin")||"*";if(request.method==="OPTIONS")return new Response(null,{headers:{"Access-Control-Allow-Origin":origin,"Access-Control-Allow-Methods":"GET,OPTIONS","Access-Control-Allow-Headers":"Content-Type"}});if(path==="/health")return cors({status:"ok",tickers:TICKERS.length,routes:["/health","/prices","/dividends","/tickers","/all"]},origin);if(path==="/tickers")return cors(TICKERS,origin);if(path==="/prices"){var sym=url.searchParams.get("symbols");if(sym){var r={};sym.split(",").map(function(s){return s.trim().toUpperCase()}).filter(Boolean).forEach(function(s){if(PRICES[s])r[s]=PRICES[s]});return cors(r,origin)}return cors(PRICES,origin)}if(path==="/dividends"){var sym=url.searchParams.get("symbols");if(sym){var r={};sym.split(",").map(function(s){return s.trim().toUpperCase()}).filter(Boolean).forEach(function(s){if(DIVS[s])r[s]=DIVS[s]});return cors(r,origin)}return cors(DIVS,origin)}if(path==="/all"){var sym=url.searchParams.get("symbols");if(sym){var r={};sym.split(",").map(function(s){return s.trim().toUpperCase()}).filter(Boolean).forEach(function(s){r[s]={prices:PRICES[s]||[],dividends:DIVS[s]||[]}});return cors(r,origin)}return cors({prices:PRICES,dividends:DIVS},origin)}return cors({error:"Routes: /health /prices /dividends /tickers /all"},origin,404)}};
